import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { Course } from '../../core/models';

@Component({
  selector: 'app-catalog',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './catalog.component.html',
  styleUrl: './catalog.component.css',
})
export class CatalogComponent {
  loading = signal(false);
  error = signal<string | null>(null);

  courses = signal<Course[]>([
    {
      id: 'c1',
      title: 'Intro to Web Development',
      description: 'Learn HTML, CSS, and JavaScript fundamentals to build your first responsive website.',
      moduleCount: 4,
      lessonCount: 12,
      enrolled: true,
      progressPct: 45,
    },
    {
      id: 'c2',
      title: 'Data Structures & Algorithms',
      description: 'Master arrays, linked lists, trees, and the core algorithms every engineer should know.',
      moduleCount: 6,
      lessonCount: 20,
      enrolled: false,
      progressPct: 0,
    },
    {
      id: 'c3',
      title: 'Designing for Accessibility',
      description: 'Practical techniques for building inclusive interfaces that work for everyone.',
      moduleCount: 3,
      lessonCount: 9,
      enrolled: false,
      progressPct: 0,
    },
    {
      id: 'c4',
      title: 'Introduction to Machine Learning',
      description: 'From linear regression to neural networks — a gentle, hands-on tour of modern ML.',
      moduleCount: 5,
      lessonCount: 15,
      enrolled: true,
      progressPct: 10,
    },
  ]);

  enroll(course: Course, ev: Event): void {
    ev.stopPropagation();
    ev.preventDefault();
    // Optimistic mock — service_agent wires this to api.enroll(course.id).
    this.courses.update((list) =>
      list.map((c) => (c.id === course.id ? { ...c, enrolled: true } : c)),
    );
  }
}
